module RefModule(
      output [7:0]DPO,     
      output [7:0]SPO,     
      input [3:0]A,       	
      input [7:0]D,        
      input [3:0]DPRA, 		
      input WCLK,   			
      input WE        		
   );reg [7:0]data[15:0];
	assign DPO = data[DPRA];
	assign SPO = data[A];

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge WCLK or posedge dbg_halt)
		if(WE) data[A] <= D;		

endmodule
